### Use Impersonated Credentials with GoogleAuth (Node.js)

Source: https://context7.com/googleapis/google-auth-library-nodejs/llms.txt

Illustrates how to use impersonated credentials with the Google Auth library. This allows a source credential to impersonate a target service account, enabling privilege delegation. The example shows how to obtain an access token and make authenticated requests using the impersonated credentials, including with gRPC client libraries.

```javascript
const {GoogleAuth, Impersonated} = require('google-auth-library');
const {SecretManagerServiceClient} = require('@google-cloud/secret-manager');

async function useImpersonatedCredentials() {
  try {
    // Acquire source credentials (e.g., from ADC)
    const auth = new GoogleAuth({
      scopes: ['https://www.googleapis.com/auth/cloud-platform']
    });
    const sourceClient = await auth.getClient();

    // Create impersonated credentials
    const targetClient = new Impersonated({
      sourceClient: sourceClient,
      targetPrincipal: 'high-privilege-sa@project-id.iam.gserviceaccount.com',
      lifetime: 3600, // Token lifetime in seconds
      delegates: [], // Optional: intermediate service accounts
      targetScopes: ['https://www.googleapis.com/auth/cloud-platform']
    });

    // Get access token for impersonated account
    const accessTokenResponse = await targetClient.getAccessToken();
    console.log('Impersonated Access Token:', accessTokenResponse.token.substring(0, 20) + '...');

    // Get request headers
    const headers = await targetClient.getRequestHeaders();
    console.log('Authorization Header:', headers.Authorization?.substring(0, 30) + '...');

    // Use with Google Cloud Storage
    const url = 'https://www.googleapis.com/storage/v1/b?project=my-project';
    const storageRes = await targetClient.fetch(url);
    console.log('Buckets accessible by impersonated SA:', storageRes.data.items?.length);

    // Use with gRPC-based client libraries
    const smClient = new SecretManagerServiceClient({
      projectId: 'my-project',
      auth: {
        getClient: () => targetClient,
      },
    });

    const secretName = 'projects/123456789/secrets/my-secret/versions/latest';
    const [accessResponse] = await smClient.accessSecretVersion({name: secretName});
    const secretPayload = accessResponse.payload.data.toString('utf8');
    console.log('Secret accessed via impersonation:', secretPayload.substring(0, 10) + '...');

  } catch (error) {
    console.error('Impersonation failed:', error.message);
    throw error;
  }
}

useImpersonatedCredentials().catch(console.error);
```

