### Load Credentials from Keyfile (Node.js)

Source: https://github.com/googleapis/google-auth-library-nodejs/blob/main/README.md

Shows how to load Google Cloud credentials from a service account keyfile. This is a common method for authenticating applications running outside of Google Cloud.

```javascript
const {GoogleAuth} = require('google-auth-library');

async function loadKeyfile() {
  const auth = new GoogleAuth({
    keyFile: 'path/to/your/keyfile.json',
    scopes: 'https://www.googleapis.com/auth/cloud-platform',
  });
  const client = await auth.getClient();
  console.log('Client obtained using keyfile.');
  // Now you can use the client to make authenticated requests
  const res = await client.request({url: 'https://storage.googleapis.com/storage/v1/b'});
  console.log('Storage buckets:', res.data.items);
}

loadKeyfile().catch(console.error);

```

